mapper.select:
SELECT TPPS.ID, TPPS.CARGO_INFO_ID, TPPS.CARGO_INFO_NO, TPPS.STOREHOUSE_ID, TPPS.STOREHOUSE_NAME, TPPS.REGION_ID, TPPS.REGION_NAME, TPPS.MASS_ID, TPPS.MASS_NAME, TPPS.QUANTITY, TPPS.TON, TPPS.CLEAN_MASS_SIGN, SUM(NVL(TPPSD.QUANTITY,0)) DETAIL_QUANTITY, SUM(NVL(TPPSD.TON,0)) DETAIL_TON FROM T_PRD_PORT_STORAGE TPPS INNER JOIN T_PRD_PORT_STORAGE_DETAIL TPPSD ON TPPS.ID = TPPSD.PORT_STORAGE_ID
TPPS.CARGO_INFO_ID = #{cargoInfoId}
GROUP BY TPPS.ID, TPPS.CARGO_INFO_ID, TPPS.CARGO_INFO_NO, TPPS.STOREHOUSE_ID, TPPS.STOREHOUSE_NAME, TPPS.REGION_ID, TPPS.REGION_NAME, TPPS.MASS_ID, TPPS.MASS_NAME, TPPS.QUANTITY, TPPS.TON, TPPS.CLEAN_MASS_SIGN, TPPS.CREATE_TIME ORDER BY TPPS.CREATE_TIME

SELECT TPPSD.ID, TPPS.CLEAN_MASS_SIGN, TPPSD.PROCESS_DETAIL_CODE, TPPSD.CARGO_TRANSFER_ID, TPPS.STOREHOUSE_ID, TPPS.STOREHOUSE_NAME, TPPS.REGION_ID, TPPS.REGION_NAME, TPPS.MASS_ID, TPPS.MASS_NAME FROM T_PRD_PORT_STORAGE TPPS INNER JOIN T_PRD_PORT_STORAGE_DETAIL TPPSD ON TPPS.ID = TPPSD.PORT_STORAGE_ID
TPPS.CARGO_INFO_ID = #{cargoInfoId}
AND TPPSD.CARGO_TRANSFER_ID = #{cargoTransferId}
AND TPPS.MASS_ID IN
#{id, jdbcType=BIGINT}

SELECT T.* FROM ( SELECT CT.ID, CT.TRANSFER_DATE, CT.CARGO_INFO_ID_SOURCE, CT.CARGO_INFO_ID_TARGET, CT.QUANTITY, CT.TON, CT.CARGO_OWNER_ID, CT.CARGO_OWNER_NAME, CT.CARGO_AGENT_ID, CT.CARGO_AGENT_NAME, CT.STORAGE_DATE, CT.STATUS, CT.REMARK, CT.CREATE_BY, CT.CREATE_BY_NAME, CT.CREATE_TIME, CT.UPDATE_BY, CT.UPDATE_BY_NAME, CT.UPDATE_TIME, CT.IS_BILLING, CT.PAYMENT_CUSTOMER_ID, CT.PAYMENT_CUSTOMER_NAME, CI1.COMPANY_ID, CI1.COMPANY_NAME, CI1.SHIPVOYAGE_ITEM_ID, (CASE WHEN CI1.SHIP_NAME IS NOT NULL AND CI1.VOYAGE IS NOT NULL THEN TO_CHAR(CI1.SHIP_NAME) || '_' || TO_CHAR(CI1.VOYAGE) ELSE '' END) SHIP_NAME_VOYAGE, CI1.CARGO_CODE, CI1.PACKING_CODE, CI1.SHIP_NAME, CI1.CARGO_NAME, CI1.TRADE_TYPE, CI1.PACKING_NAME,
CI1.CARGO_OWNER_ID CARGO_OWNER_ID_SOURCE, CI1.CARGO_OWNER_NAME CARGO_OWNER_NAME_SOURCE, CI1.CARGO_AGENT_ID CARGO_AGENT_ID_SOURCE, CI1.CARGO_AGENT_NAME CARGO_AGENT_NAME_SOURCE, CI1.CARGO_INFO_NO AS SOURCE_CARGO_INFO_NO,
CI2.CARGO_OWNER_ID CARGO_OWNER_ID_TARGET, CI2.CARGO_OWNER_NAME CARGO_OWNER_NAME_TARGET, CI2.CARGO_AGENT_ID CARGO_AGENT_ID_TARGET, CI2.CARGO_AGENT_NAME CARGO_AGENT_NAME_TARGET, CI2.CARGO_INFO_NO AS TARGET_CARGO_INFO_NO, LISTAGG(TPPS.MASS_NAME,',') WITHIN GROUP (ORDER BY TPPS.MASS_NAME) MASS_NAME FROM T_BUS_CARGO_TRANSFER CT INNER JOIN T_BUS_CARGO_INFO CI1 ON CI1.ID = CT.CARGO_INFO_ID_SOURCE LEFT JOIN T_BUS_CARGO_INFO CI2 ON CI2.ID = CT.CARGO_INFO_ID_TARGET LEFT JOIN ( SELECT DISTINCT T1.CARGO_INFO_ID,T1.MASS_NAME FROM T_PRD_PORT_STORAGE T1 INNER JOIN T_PRD_PORT_STORAGE_DETAIL T2 ON T1.ID = T2.PORT_STORAGE_ID ) TPPS ON CT.CARGO_INFO_ID_SOURCE = TPPS.CARGO_INFO_ID
and TO_CHAR(CT.TRANSFER_DATE, 'YYYY-MM-DD') >= #{transferDate}
and CI1.CARGO_OWNER_ID = #{oldCargoOwnerId}
and CT.CARGO_OWNER_ID = #{cargoOwnerId}
and CI1.CARGO_CODE = #{cargoCode}
and CI1.TRADE_TYPE = #{tradeType}
and CT.STATUS = #{status}
and CT.STATUS != '1'
and CI1.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}
AND CI1.SHIP_NAME LIKE #{shipName_like}
AND CI1.VOYAGE LIKE #{voyage_like}
and (CI1.CARGO_INFO_NO LIKE #{cargoInfoNoLike} OR CI2.CARGO_INFO_NO LIKE #{cargoInfoNoLike})
GROUP BY CT.ID, CT.TRANSFER_DATE, CT.CARGO_INFO_ID_SOURCE, CT.CARGO_INFO_ID_TARGET, CT.QUANTITY, CT.TON, CT.CARGO_OWNER_ID, CT.CARGO_OWNER_NAME, CT.CARGO_AGENT_ID, CT.CARGO_AGENT_NAME, CT.STORAGE_DATE, CT.STATUS, CT.REMARK, CT.CREATE_BY, CT.CREATE_BY_NAME, CT.CREATE_TIME, CT.UPDATE_BY, CT.UPDATE_BY_NAME, CT.UPDATE_TIME, CT.IS_BILLING, CT.PAYMENT_CUSTOMER_ID, CT.PAYMENT_CUSTOMER_NAME, CI1.SHIP_NAME, CI1.CARGO_NAME, CI1.TRADE_TYPE, CI1.PACKING_NAME, CI1.CARGO_OWNER_ID, CI1.CARGO_OWNER_NAME, CI1.CARGO_AGENT_ID, CI1.CARGO_AGENT_NAME, CI1.CARGO_INFO_NO, CI2.CARGO_OWNER_ID, CI2.CARGO_OWNER_NAME, CI2.CARGO_AGENT_ID, CI2.CARGO_AGENT_NAME, CI2.CARGO_INFO_NO, CI1.COMPANY_ID, CI1.COMPANY_NAME, CI1.SHIPVOYAGE_ITEM_ID, CI1.CARGO_CODE, CI1.PACKING_CODE, CI1.VOYAGE ) T ORDER BY T.CREATE_TIME DESC

mapper.update:
UPDATE T_BUS_CARGO_TRANSFER SET CARGO_INFO_ID_TARGET = #{cargoInfoIdTarget,jdbcType=BIGINT}, STATUS = #{status,jdbcType=VARCHAR}, UPDATE_BY = #{loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{now}, APPROVAL_BY = #{loginUserId, jdbcType=BIGINT}, APPROVAL_BY_NAME = #{loginUserName, jdbcType=VARCHAR}, APPROVAL_TIME = #{now}
,CARGO_SOURCE = #{cargoSource, jdbcType=VARCHAR}
,SOURCE_STORAGE_DATE = #{sourceStorageDate, jdbcType=DATE}
id = #{id}

mapper.select:
SELECT V.WEIGH_OUT_DT,V.WEIGHT_GOODS
FROM V_WEIGHT_INFO V
INNER JOIN T_BUS_TRUST_CARGO TBTC ON V.PLAN_NO = TBTC.BUSINESS_NO

    TBTC.TRUST_ID = #{trustId, jdbcType=BIGINT}
    AND TBTC.CARGO_INFO_ID = #{cargoInfoId, jdbcType=BIGINT}

ORDER BY V.WEIGH_OUT_DT ASC

SELECT V.WEIGH_OUT_DT,V.WEIGHT_GOODS FROM V_WEIGHT_INFO V
V.IS_OLD = '是' AND V.CARGO_INFO_ID = #{cargoInfoId, jdbcType=BIGINT}
ORDER BY V.WEIGH_OUT_DT ASC
